const checkpoints = [];

function parseJSON(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return fallback;
  try { return JSON.parse(raw); } catch (e) { return fallback; }
}

const appointments = parseJSON('appointments', []);
const locations = parseJSON('locations', []);
const services = parseJSON('services', []);
const servicePackages = parseJSON('service_packages', []);
const offerings = parseJSON('location_service_offerings', []);
const timeSlots = parseJSON('appointment_time_slots', []);
const locationHours = parseJSON('location_hours', []);

const searchZip = '30301';
const minRating = 4.5;
const maxPrice = 70;
const targetDate = '2026-03-07';
const windowStart = '09:00';
const windowEnd = '11:00';

function cmpTime(a, b) { return String(a).localeCompare(String(b)); }

// Oil change service/package ids
const oilChangeServiceIds = services
  .filter(s => s.category_id === 'oil_changes')
  .map(s => s.id);

const oilChangePackageIds = servicePackages
  .filter(sp => oilChangeServiceIds.includes(sp.service_id))
  .map(sp => sp.id);

function orderLocationsByZip(allLocs, zip) {
  const exactZip = allLocs.filter(l => l.zip === zip);
  const cityMatches = allLocs.filter(l => l.zip !== zip && l.city && l.city.toLowerCase() === String(zip).toLowerCase());
  const others = allLocs.filter(l => !exactZip.includes(l) && !cityMatches.includes(l));
  return exactZip.concat(cityMatches, others);
}

// Locations that can actually provide an oil change under max price in the requested window/date
const eligibleLocations = locations.filter(loc => {
  if (!loc.is_active || loc.average_rating < minRating) return false;

  const locOfferings = offerings.filter(o =>
    o.location_id === loc.id &&
    oilChangePackageIds.includes(o.service_package_id) &&
    o.is_available &&
    typeof o.price === 'number' && o.price <= maxPrice
  );
  if (!locOfferings.length) return false;

  const pkgIdsForLoc = locOfferings.map(o => o.service_package_id);
  const slotsForLoc = timeSlots.filter(ts =>
    ts.is_available &&
    ts.location_id === loc.id &&
    pkgIdsForLoc.includes(ts.service_package_id) &&
    ts.start_datetime.slice(0, 10) === targetDate
  );
  if (!slotsForLoc.length) return false;

  const hasSlotInWindow = slotsForLoc.some(ts => {
    const t = ts.start_datetime.slice(11, 16);
    return cmpTime(t, windowStart) >= 0 && cmpTime(t, windowEnd) <= 0;
  });

  return hasSlotInWindow;
});

let expectedLocationId = null;
if (eligibleLocations.length) {
  const ordered = orderLocationsByZip(eligibleLocations, searchZip);
  expectedLocationId = ordered.length ? ordered[0].id : null;
}

const qualifyingAppointments = appointments.filter(appt => {
  if (!expectedLocationId) return false;
  if (appt.location_id !== expectedLocationId) return false;
  if (typeof appt.price !== 'number' || appt.price > maxPrice) return false;

  const sp = servicePackages.find(sp => sp.id === appt.service_package_id);
  if (!sp) return false;
  const svc = services.find(s => s.id === sp.service_id);
  if (!svc || svc.category_id !== 'oil_changes') return false;

  const dt = appt.appointment_datetime || '';
  if (dt.slice(0, 10) !== targetDate) return false;
  const timePart = dt.slice(11, 16);
  if (cmpTime(timePart, windowStart) < 0 || cmpTime(timePart, windowEnd) > 0) return false;

  return true;
});

// Single checkpoint: fully qualifying appointment exists
checkpoints.push({ passed: qualifyingAppointments.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

