const coupons = parseJSON('coupons', []);
const servicePackages = parseJSON('service_packages', []);
const services = parseJSON('services', []);
const checkoutViewedRaw = localStorage.getItem('task2_checkoutViewed');
const checkoutViewed = (checkoutViewedRaw === 'true' || checkoutViewedRaw === '1' || checkoutViewedRaw === true);

// Qualifying brake coupons (percent_off >= 15)
const qualifyingBrakeCoupons = coupons.filter(c =>
  c.category === 'brakes' &&
  c.discount_type === 'percent_off' &&
  typeof c.discount_value === 'number' && c.discount_value >= 15 &&
  c.is_active
);

const firstBrakeCouponId = qualifyingBrakeCoupons.length ? qualifyingBrakeCoupons[0].id : null;

// Cart items that use that first coupon on a front brake pad replacement package under $350
const qualifyingCartItems = cartItems.filter(ci => {
  if (!cart || ci.cart_id !== cart.id) return false;
  if (ci.item_type !== 'service_with_coupon' || !ci.coupon_id || !ci.service_package_id) return false;

  const coupon = coupons.find(c => c.id === ci.coupon_id);
  if (!coupon || coupon.id !== firstBrakeCouponId) return false;

  const sp = servicePackages.find(sp => sp.id === ci.service_package_id);
  if (!sp || typeof sp.base_price !== 'number' || sp.base_price > 350) return false;

  const svc = services.find(s => s.id === sp.service_id);
  if (!svc) return false;

  const isFrontBrakePad = (svc.category_id === 'brakes' &&
    typeof svc.name === 'string' &&
    svc.name.toLowerCase().includes('front brake pad replacement'));

  return isFrontBrakePad;
});

const hasCorrectServiceWithCoupon = qualifyingCartItems.length > 0;

// CP1 (0.6): Correct front brake pad service with first qualifying brake coupon added to active cart
checkpoints.push({ passed: hasCorrectServiceWithCoupon, weight: 0.6 });

// CP2 (0.4): User viewed checkout summary after adding the correct item
checkpoints.push({ passed: hasCorrectServiceWithCoupon && checkoutViewed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

