const cart = parseJSON('cart', null);
const cartItems = parseJSON('cart_items', []);
const plans = parseJSON('maintenance_plans', []);
const vehicles = parseJSON('vehicles', []);

const cartViewedRaw = localStorage.getItem('task3_cartViewed');
const checkoutViewedRaw = localStorage.getItem('task3_checkoutViewed');
const cartViewed = (cartViewedRaw === 'true' || cartViewedRaw === '1' || cartViewedRaw === true);
const checkoutViewed = (checkoutViewedRaw === 'true' || checkoutViewedRaw === '1' || checkoutViewedRaw === true);

// Plans for 2018 Honda Civic (as shown to the user)
const civicVehicleIds = vehicles
  .filter(v => v.year === 2018 && v.make === 'Honda' && v.model === 'Civic')
  .map(v => v.id);

const civicPlansInOrder = plans.filter(p =>
  p.is_active &&
  Array.isArray(p.vehicle_ids) &&
  p.vehicle_ids.some(vid => civicVehicleIds.includes(vid))
);

const firstTwo = civicPlansInOrder.slice(0, 2);

let bestPlanId = null;
if (firstTwo.length >= 1) {
  const underCap = firstTwo.filter(p => typeof p.monthly_price === 'number' && p.monthly_price < 50);
  if (underCap.length) {
    underCap.sort((a, b) => {
      if ((a.warranty_months || 0) !== (b.warranty_months || 0)) {
        return (b.warranty_months || 0) - (a.warranty_months || 0);
      }
      return (a.monthly_price || 0) - (b.monthly_price || 0);
    });
    bestPlanId = underCap[0].id;
  }
}

const qualifyingPlanItems = cartItems.filter(ci => {
  if (!cart || ci.cart_id !== cart.id) return false;
  if (ci.item_type !== 'maintenance_plan' || !ci.maintenance_plan_id) return false;
  if (!bestPlanId || ci.maintenance_plan_id !== bestPlanId) return false;
  const plan = plans.find(p => p.id === ci.maintenance_plan_id);
  if (!plan) return false;
  const inFirstTwo = firstTwo.some(p => p.id === plan.id);
  return inFirstTwo && typeof plan.monthly_price === 'number' && plan.monthly_price < 50;
});

const hasCorrectPlanInCart = qualifyingPlanItems.length > 0;

// CP1 (0.5): Correct Civic maintenance plan (longest warranty under $50 from first two) added to cart
checkpoints.push({ passed: hasCorrectPlanInCart, weight: 0.5 });

// CP2 (0.25): Cart viewed after adding correct plan
checkpoints.push({ passed: hasCorrectPlanInCart && cartViewed, weight: 0.25 });

// CP3 (0.25): Checkout summary viewed after adding correct plan
checkpoints.push({ passed: hasCorrectPlanInCart && checkoutViewed, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

