function cmpTime(a, b) { return String(a).localeCompare(String(b)); }

const quoteRequests = parseJSON('quote_requests', []);
const services = parseJSON('services', []);
const locations = parseJSON('locations', []);
const timeSlots = parseJSON('appointment_time_slots', []);
const servicePackages = parseJSON('service_packages', []);

const diagService = services.find(s => s.category_id === 'diagnostics' && s.is_quote_only);
const diagServiceId = diagService ? diagService.id : null;

const loopLocation = locations.find(l => l.zip === '60601') || null;
const loopLocationId = loopLocation ? loopLocation.id : null;

// Compute earliest available diagnostics slot within next 3 days, 08:00–10:00, at 60601 location
let earliestSlotStart = null;
if (diagServiceId && loopLocationId) {
  const pkgIds = servicePackages
    .filter(sp => sp.service_id === diagServiceId && sp.is_active)
    .map(sp => sp.id);

  if (pkgIds.length) {
    const now = new Date();
    const endDate = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000);

    const candidateSlots = timeSlots.filter(ts => {
      if (!ts.is_available) return false;
      if (ts.location_id !== loopLocationId) return false;
      if (!pkgIds.includes(ts.service_package_id)) return false;
      const start = new Date(ts.start_datetime);
      if (isNaN(start.getTime())) return false;
      if (start < now || start > endDate) return false;
      const timePart = ts.start_datetime.slice(11, 16);
      if (cmpTime(timePart, '08:00') < 0 || cmpTime(timePart, '10:00') > 0) return false;
      return true;
    }).sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));

    if (candidateSlots.length) {
      earliestSlotStart = candidateSlots[0].start_datetime;
    }
  }
}

// Quote requests matching service, location, drop-off, time window, and with contact + issue filled
const windowRequests = quoteRequests.filter(q => {
  if (!diagServiceId || !loopLocationId) return false;
  if (q.service_id !== diagServiceId) return false;
  if (q.location_id !== loopLocationId) return false;
  if (q.visit_type !== 'drop_off') return false;

  if (!q.name || !q.phone || !q.email) return false;
  if (!q.issue_description) return false;

  const dt = new Date(q.requested_datetime);
  if (isNaN(dt.getTime())) return false;

  const now = new Date();
  const endDate = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000);
  if (dt < now || dt > endDate) return false;

  const timePart = q.requested_datetime.slice(11, 16);
  if (cmpTime(timePart, '08:00') < 0 || cmpTime(timePart, '10:00') > 0) return false;

  return true;
});

const hasQualifyingRequest = windowRequests.length > 0;

// CP1 (0.6): Submitted a diagnostics quote request at 60601 for drop-off within 3 days, 8–10 AM, with contact and issue details
checkpoints.push({ passed: hasQualifyingRequest, weight: 0.6 });

// CP2 (0.4): Among qualifying requests, the chosen time matches the earliest available slot
let matchesEarliest = false;
if (hasQualifyingRequest && earliestSlotStart) {
  const earliestRequest = windowRequests.slice().sort(
    (a, b) => new Date(a.requested_datetime) - new Date(b.requested_datetime)
  )[0];
  matchesEarliest = earliestRequest.requested_datetime === earliestSlotStart;
}
checkpoints.push({ passed: hasQualifyingRequest && matchesEarliest, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

