const appointments = parseJSON('appointments', []);
const locations = parseJSON('locations', []);
const services = parseJSON('services', []);
const servicePackages = parseJSON('service_packages', []);
const offerings = parseJSON('location_service_offerings', []);
const timeSlots = parseJSON('appointment_time_slots', []);
const locationHours = parseJSON('location_hours', []);

// Flat tire repair service & packages
const flatService = services.find(s => s.category_id === 'tires_wheels' && typeof s.name === 'string' && s.name.toLowerCase().includes('flat tire'));
const flatServiceId = flatService ? flatService.id : null;
const flatPackageIds = servicePackages
  .filter(sp => flatServiceId && sp.service_id === flatServiceId && sp.is_active)
  .map(sp => sp.id);

const now = new Date();
const todayStr = now.toISOString().slice(0, 10);
const days = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const todayDow = days[now.getDay()];

// Locations that are open today and close at or after 19:00 and offer flat repair
const candidateLocations = locations.filter(loc => {
  if (!loc.is_active) return false;
  const hours = locationHours.find(h => h.location_id === loc.id && h.day_of_week === todayDow && !h.is_closed);
  if (!hours) return false;
  if (cmpTime(hours.close_time, '19:00') < 0) return false;
  const hasOffering = offerings.some(o =>
    o.location_id === loc.id &&
    flatPackageIds.includes(o.service_package_id) &&
    o.is_available
  );
  return hasOffering;
});

const candidateLocationIds = candidateLocations.map(l => l.id);

// Available flat repair slots today after 18:00 at candidate locations
const candidateSlots = timeSlots.filter(ts => {
  if (!ts.is_available) return false;
  if (!candidateLocationIds.includes(ts.location_id)) return false;
  if (!flatPackageIds.includes(ts.service_package_id)) return false;
  if (ts.start_datetime.slice(0, 10) !== todayStr) return false;
  const timePart = ts.start_datetime.slice(11, 16);
  if (cmpTime(timePart, '18:00') < 0) return false;
  return true;
});

let bestSlot = null;
if (candidateSlots.length) {
  candidateSlots.sort((a, b) => {
    if ((a.price || 0) !== (b.price || 0)) {
      return (a.price || 0) - (b.price || 0);
    }
    return new Date(a.start_datetime) - new Date(b.start_datetime);
  });
  bestSlot = candidateSlots[0];
}

// Appointments for flat repair today after 18:00 at candidate locations
const apptsInWindow = appointments.filter(appt => {
  if (!flatPackageIds.includes(appt.service_package_id)) return false;
  if (!candidateLocationIds.includes(appt.location_id)) return false;
  const dt = appt.appointment_datetime || '';
  if (dt.slice(0, 10) !== todayStr) return false;
  const timePart = dt.slice(11, 16);
  if (cmpTime(timePart, '18:00') < 0) return false;
  return true;
});

// CP1 (0.4): Booked any flat tire repair today after 6 PM at a shop open until at least 7 PM
checkpoints.push({ passed: apptsInWindow.length > 0, weight: 0.4 });

// CP2 (0.3): At least one appointment uses the lowest-priced eligible slot after 6 PM
let hasLowestPrice = false;
if (apptsInWindow.length && bestSlot) {
  hasLowestPrice = apptsInWindow.some(a =>
    a.location_id === bestSlot.location_id &&
    a.service_package_id === bestSlot.service_package_id &&
    a.appointment_datetime === bestSlot.start_datetime &&
    typeof a.price === 'number' && a.price === bestSlot.price
  );
}
checkpoints.push({ passed: hasLowestPrice, weight: 0.3 });

// CP3 (0.3): If multiple slots share that lowest price, the booked one is the earliest among them
let hasEarliestAtLowestPrice = false;
if (apptsInWindow.length && bestSlot) {
  const lowestPrice = bestSlot.price;
  const lowestPriceSlots = candidateSlots.filter(s => s.price === lowestPrice);
  lowestPriceSlots.sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));
  const earliestLowestSlot = lowestPriceSlots[0];

  hasEarliestAtLowestPrice = apptsInWindow.some(a =>
    a.location_id === earliestLowestSlot.location_id &&
    a.service_package_id === earliestLowestSlot.service_package_id &&
    a.appointment_datetime === earliestLowestSlot.start_datetime &&
    a.price === earliestLowestSlot.price
  );
}
checkpoints.push({ passed: hasLowestPrice && hasEarliestAtLowestPrice, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

