const appointments = parseJSON('appointments', []);
const locations = parseJSON('locations', []);
const services = parseJSON('services', []);
const servicePackages = parseJSON('service_packages', []);
const offerings = parseJSON('location_service_offerings', []);

const searchZip = '75201';
const maxPrice = 200;
const minShuttleRadius = 5;

// 30k-mile maintenance service and packages under price cap
const maintService = services.find(s => s.category_id === 'scheduled_maintenance' && typeof s.name === 'string' && s.name.toLowerCase().includes('30,000-mile'));
const maintServiceId = maintService ? maintService.id : null;

const maintPackages = servicePackages.filter(sp =>
  maintServiceId &&
  sp.service_id === maintServiceId &&
  sp.is_active &&
  typeof sp.base_price === 'number' && sp.base_price <= maxPrice
);
const maintPackageIds = maintPackages.map(sp => sp.id);

// Locations with free shuttle within radius that offer one of these packages under cap
const candidateLocations = locations.filter(loc => {
  if (!loc.is_active || !loc.offers_free_shuttle) return false;
  if (typeof loc.shuttle_radius_miles !== 'number' || loc.shuttle_radius_miles < minShuttleRadius) return false;
  const hasOffering = offerings.some(o =>
    o.location_id === loc.id &&
    maintPackageIds.includes(o.service_package_id) &&
    o.is_available &&
    typeof o.price === 'number' && o.price <= maxPrice
  );
  return hasOffering;
});

let expectedLocationId = null;
if (candidateLocations.length) {
  const ordered = orderLocationsByZip(candidateLocations, searchZip);
  expectedLocationId = ordered.length ? ordered[0].id : null;
}

// Appointments matching 30k service, shuttle visit, under price cap, with non-empty pickup address at shuttle-enabled shops
const shuttleAppointments = appointments.filter(appt => {
  if (!maintPackageIds.includes(appt.service_package_id)) return false;
  const loc = locations.find(l => l.id === appt.location_id);
  if (!loc) return false;
  if (!loc.offers_free_shuttle) return false;
  if (typeof loc.shuttle_radius_miles !== 'number' || loc.shuttle_radius_miles < minShuttleRadius) return false;

  const off = offerings.find(o =>
    o.location_id === loc.id &&
    o.service_package_id === appt.service_package_id &&
    typeof o.price === 'number' && o.price <= maxPrice
  );
  if (!off) return false;

  if (appt.visit_type !== 'shuttle') return false;
  if (typeof appt.shuttle_pickup_address !== 'string' || !appt.shuttle_pickup_address.trim()) return false;

  return true;
});

const hasQualifyingShuttleAppt = shuttleAppointments.length > 0;

// CP1 (0.7): Scheduled a 30k-mile maintenance appointment under $200 with shuttle visit and pickup address at a free-shuttle shop within 5 miles
checkpoints.push({ passed: hasQualifyingShuttleAppt, weight: 0.7 });

// CP2 (0.3): Appointment is at the nearest qualifying shuttle-enabled location to ZIP 75201
let atNearestLocation = false;
if (hasQualifyingShuttleAppt && expectedLocationId) {
  atNearestLocation = shuttleAppointments.some(a => a.location_id === expectedLocationId);
}
checkpoints.push({ passed: hasQualifyingShuttleAppt && atNearestLocation, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

