const cart = parseJSON('cart', null);
const cartItems = parseJSON('cart_items', []);
const giftCardProducts = parseJSON('gift_card_products', []);
const giftCards = parseJSON('gift_cards', []);
const checkoutViewedRaw = localStorage.getItem('task7_checkoutViewed');
const checkoutViewed = (checkoutViewedRaw === 'true' || checkoutViewedRaw === '1' || checkoutViewedRaw === true);

const amountRequired = 100;

// Active email gift card products that allow $100
const emailProducts = giftCardProducts.filter(p =>
  p.is_active &&
  p.delivery_method === 'email' &&
  (
    (Array.isArray(p.preset_amounts) && p.preset_amounts.includes(amountRequired)) ||
    (!p.preset_amounts || !p.preset_amounts.length)
  )
);
const emailProductIds = emailProducts.map(p => p.id);

// Configured email gift cards for $100 with recipient & sender details
const qualifyingGiftCards = giftCards.filter(gc => {
  if (!emailProductIds.includes(gc.gift_card_product_id)) return false;
  if (gc.delivery_method !== 'email') return false;
  if (gc.amount !== amountRequired) return false;
  if (!gc.recipient_name || !gc.recipient_email) return false;
  if (!gc.sender_name || !gc.sender_email) return false;
  if (typeof gc.recipient_email !== 'string' || !gc.recipient_email.includes('@')) return false;
  if (typeof gc.sender_email !== 'string' || !gc.sender_email.includes('@')) return false;
  return true;
});

const qualifyingGiftCardIds = qualifyingGiftCards.map(gc => gc.id);

const qualifyingCartItems = cartItems.filter(ci => {
  if (!cart || ci.cart_id !== cart.id) return false;
  if (ci.item_type !== 'gift_card') return false;
  if (!qualifyingGiftCardIds.includes(ci.gift_card_id)) return false;
  if (typeof ci.unit_price !== 'number' || typeof ci.total_price !== 'number') return false;
  if (ci.unit_price !== amountRequired || ci.total_price !== amountRequired) return false;
  return true;
});

const hasGiftCardInCart = qualifyingCartItems.length > 0;

// CP1 (0.6): Configured a $100 email gift card with recipient and sender details and added it to the cart
checkpoints.push({ passed: hasGiftCardInCart, weight: 0.6 });

// CP2 (0.4): Viewed checkout summary after adding the correct gift card
checkpoints.push({ passed: hasGiftCardInCart && checkoutViewed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

